css:
.editor {
  background-color: #2d2d2d;
  color: #d3d0c8;
}
.editor .tasks.text {
  color: #d3d0c8;
}
.editor .tasks.marker {
  color: #d3d0c8;
}
.editor .gutter {
  background-color: #2d2d2d;
  color: #d3d0c8;
}
.editor .gutter .line-number.cursor-line {
  background-color: #393939;
  color: #d3d0c8;
}
.editor .gutter .line-number.cursor-line-no-selection {
  color: #d3d0c8;
}
.editor .wrap-guide {
  color: #747369;
}
.editor .indent-guide {
  color: #747369;
}
.editor .invisible-character {
  color: #555555;
}
.editor .search-results .marker .region {
  background-color: transparent;
  border: #747369;
}
.editor .search-results .marker.current-result .region {
  border: #d3d0c8;
}
.editor.is-focused .cursor {
  border-color: #d3d0c8;
}
.editor.is-focused .selection .region {
  background-color: #515151;
}
.editor.is-focused .line-number.cursor-line-no-selection,
.editor.is-focused .line.cursor-line {
  background-color: #393939;
}
.variable.parameter.function {
  color: #d3d0c8;
}
.comment,
.punctuation.definition.comment {
  color: #747369;
}
.punctuation.definition.string,
.punctuation.definition.variable,
.punctuation.definition.string,
.punctuation.definition.parameters,
.punctuation.definition.string,
.punctuation.definition.array {
  color: #d3d0c8;
}
.none {
  color: #d3d0c8;
}
.keyword.operator {
  color: #d3d0c8;
}
.keyword {
  color: #cc99cc;
}
.variable {
  color: #c0c5ce;
}
.entity.name.function,
.meta.require,
.support.function.any-method {
  color: #6699cc;
}
.support.class,
.entity.name.class,
.entity.name.type.class {
  color: #ffcc66;
}
.meta.class {
  color: #f2f0ec;
}
.keyword.other.special-method {
  color: #6699cc;
}
.storage {
  color: #cc99cc;
}
.support.function {
  color: #66cccc;
}
.string,
.constant.other.symbol,
.entity.other.inherited-class {
  color: #99cc99;
}
.constant.numeric {
  color: #f99157;
}
.none {
  color: #f99157;
}
.none {
  color: #f99157;
}
.constant {
  color: #f99157;
}
.entity.name.tag {
  color: #f2777a;
}
.entity.other.attribute-name {
  color: #f99157;
}
.entity.other.attribute-name.id,
.punctuation.definition.entity {
  color: #6699cc;
}
.meta.selector {
  color: #cc99cc;
}
.none {
  color: #f99157;
}
.markup.heading .punctuation.definition.heading,
.entity.name.section {
  color: #6699cc;
}
.keyword.other.unit {
  color: #f99157;
}
.markup.bold,
.punctuation.definition.bold {
  font-weight: bold;
  color: #ffcc66;
}
.markup.italic,
.punctuation.definition.italic {
  font-style: italic;
  color: #cc99cc;
}
.markup.raw.inline {
  color: #99cc99;
}
.string.other.link {
  color: #f2777a;
}
.meta.link {
  color: #f99157;
}
.markup.list {
  color: #f2777a;
}
.markup.quote {
  color: #f99157;
}
.meta.separator {
  color: #d3d0c8;
  background-color: #515151;
}
.markup.inserted {
  color: #99cc99;
}
.markup.deleted {
  color: #f2777a;
}
.markup.changed {
  color: #cc99cc;
}
.constant.other.color {
  color: #66cccc;
}
.string.regexp {
  color: #66cccc;
}
.constant.character.escape {
  color: #66cccc;
}
.punctuation.section.embedded,
.variable.interpolation {
  color: #d27b53;
}
.invalid.illegal {
  color: #2d2d2d;
  background-color: #f2777a;
}
.sublimelinter.mark.error {
  color: #D02000;
}
.sublimelinter.gutter-mark {
  color: #FFFFFF;
}
.sublimelinter.mark.warning {
  color: #DDB700;
}
